#!/usr/bin/env node
const { spawn } = require("child_process");
const fs = require("fs");
const path = require("path");

const root = __dirname;
const envFile = ".env.mimo.local";
const configPath = path.join(root, envFile);

// Load .env.mimo.local
if (fs.existsSync(configPath)) {
  const lines = fs.readFileSync(configPath, "utf-8").split("\n");
  for (const raw of lines) {
    const line = raw.trim();
    if (!line || line.startsWith("#")) continue;
    const idx = line.indexOf("=");
    if (idx === -1) continue;
    const key = line.slice(0, idx).trim();
    let val = line.slice(idx + 1).trim();
    if (
      (val.startsWith('"') && val.endsWith('"')) ||
      (val.startsWith("'") && val.endsWith("'"))
    ) {
      val = val.slice(1, -1);
    }
    process.env[key] = val;
  }
} else {
  console.error(`Missing ${configPath}`);
  process.exit(1);
}

// Defaults
if (!process.env.CLAUDE_CONFIG_DIR) {
  process.env.CLAUDE_CONFIG_DIR = path.join(
    process.env.USERPROFILE || process.env.HOME || "",
    ".claude"
  );
}
process.env.npm_config_cache = process.env.npm_config_cache || "E:\\CC-test\\.npm-cache";
process.env.TERM = process.env.TERM || "xterm-256color";
process.env.COLORTERM = process.env.COLORTERM || "truecolor";
process.env.CLAUDE_CODE_NATIVE_CURSOR = process.env.CLAUDE_CODE_NATIVE_CURSOR || "1";
process.env.CLAUDE_CODE_NO_FLICKER = process.env.CLAUDE_CODE_NO_FLICKER || "1";
process.env.CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC =
  process.env.CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC || "1";
process.env.DISABLE_TELEMETRY = process.env.DISABLE_TELEMETRY || "1";

// Find claude CLI
const preferredCmd = "E:\\CC-test\\npm-global\\claude.cmd";
const fallbackCmd = path.join(root, "node_modules", ".bin", "claude.cmd");

let claudeCmd;
if (fs.existsSync(preferredCmd)) {
  claudeCmd = preferredCmd;
} else if (fs.existsSync(fallbackCmd)) {
  claudeCmd = fallbackCmd;
} else {
  console.error(
    "Claude Code CLI was not found. Install with: npm install -g @anthropic-ai/claude-code --prefix E:\\CC-test\\npm-global --cache E:\\CC-test\\.npm-cache"
  );
  process.exit(1);
}

// Build args: skip first arg if it's claude.exe or cli.js (extension passes it)
let args = process.argv.slice(2);
if (args.length > 0) {
  const first = args[0];
  if (
    /(?:^|[\/\\])claude(?:\.exe)?$/i.test(first) ||
    /(?:^|[\/\\])cli\.js$/i.test(first)
  ) {
    args = args.slice(1);
  }
}

// Spawn claude.cmd via cmd.exe (required on Windows for .cmd files)
const child = spawn("cmd.exe", ["/c", claudeCmd, ...args], {
  stdio: "inherit",
  env: process.env,
  windowsHide: false,
});

child.on("close", (code) => {
  process.exit(code || 0);
});

child.on("error", (err) => {
  console.error("Failed to start Claude:", err.message);
  process.exit(1);
});

