const fs = require('fs');
const path = require('path');
const { spawn } = require('child_process');

const root = __dirname;
const logPath = path.join(root, 'mimo-wrapper-debug.log');

function log(msg) {
  try { fs.appendFileSync(logPath, `[${new Date().toISOString()}] ${msg}\n`); } catch (_) {}
}

try {
  log('=== WRAPPER STARTED ===');
  log(`process.argv: ${JSON.stringify(process.argv)}`);
  log(`cwd: ${process.cwd()}`);

  // Load .env.mimo.local
  const configPath = path.join(root, '.env.mimo.local');
  if (fs.existsSync(configPath)) {
    const lines = fs.readFileSync(configPath, 'utf-8').split('\n');
    for (const raw of lines) {
      const line = raw.trim();
      if (!line || line.startsWith('#')) continue;
      const idx = line.indexOf('=');
      if (idx < 1) continue;
      const name = line.substring(0, idx).trim();
      let value = line.substring(idx + 1).trim();
      if ((value.startsWith('"') && value.endsWith('"')) ||
          (value.startsWith("'") && value.endsWith("'"))) {
        value = value.slice(1, -1);
      }
      process.env[name] = value;
    }
    log(`Loaded env from ${configPath}`);
  } else {
    log(`WARN: ${configPath} not found`);
  }

  // Set defaults
  if (!process.env.CLAUDE_CONFIG_DIR) {
    process.env.CLAUDE_CONFIG_DIR = path.join(process.env.USERPROFILE || '', '.claude');
  }
  process.env.npm_config_cache = 'E:\\CC-test\\.npm-cache';
  process.env.TERM = process.env.TERM || 'xterm-256color';
  process.env.COLORTERM = process.env.COLORTERM || 'truecolor';
  process.env.CLAUDE_CODE_NATIVE_CURSOR = '1';
  process.env.CLAUDE_CODE_NO_FLICKER = '1';
  process.env.CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC = '1';
  process.env.DISABLE_TELEMETRY = '1';

  log(`ANTHROPIC_BASE_URL=${process.env.ANTHROPIC_BASE_URL}`);
  log(`ANTHROPIC_MODEL=${process.env.ANTHROPIC_MODEL}`);
  log(`ANTHROPIC_AUTH_TOKEN=${process.env.ANTHROPIC_AUTH_TOKEN ? process.env.ANTHROPIC_AUTH_TOKEN.slice(0, 10) + '...' : 'undefined'}`);

  // Find claude.exe directly
  const preferredExe = 'E:\\CC-test\\npm-global\\node_modules\\@anthropic-ai\\claude-code\\bin\\claude.exe';
  const fallbackExe = path.join(root, 'node_modules', '@anthropic-ai', 'claude-code', 'bin', 'claude.exe');

  let claudeExe;
  if (fs.existsSync(preferredExe)) {
    claudeExe = preferredExe;
  } else if (fs.existsSync(fallbackExe)) {
    claudeExe = fallbackExe;
  } else {
    log('ERROR: claude.exe not found');
    process.exit(1);
  }
  log(`claudeExe: ${claudeExe}`);

  // Filter args - skip claude.exe if passed as first arg
  let args = process.argv.slice(2);
  if (args.length > 0) {
    const first = args[0];
    if (/(^|[\/\\])claude(\.exe)?$/i.test(first) || /(^|[\/\\])cli\.js$/i.test(first)) {
      args = args.slice(1);
    }
  }
  log(`filtered args: ${JSON.stringify(args)}`);

  // Spawn claude.exe directly
  const child = spawn(claudeExe, args, {
    stdio: 'inherit',
    env: process.env,
    windowsHide: false
  });

  log(`child pid: ${child.pid}`);

  child.on('exit', (code) => {
    log(`child exited with code: ${code}`);
    process.exit(code || 0);
  });

  child.on('error', (err) => {
    log(`child error: ${err.message}`);
    process.exit(1);
  });

} catch (err) {
  log(`FATAL: ${err.stack || err.message}`);
  process.exit(1);
}

